"execution statistics:" AND "openAI"

| kubernetes.container.name := #kubernetes.container.name

| drop(#kubernetes.container.name) //aks repository restructure - line can be deleted after 2025-06-01 

| kubernetes.container.name=/$container/i

| #kubernetes.namespace=/$namespace/i

| #kubernetes.cluster=/$cluster/i

| kubernetes.pod_labels.release=$release

| regex(field=message, "execution statistics: {(?:.*?'redis':\\s*(?<redis>\\d+\\.\\d+))?(?:.*?'redis\\.rate_limit':\\s*(?<redis_rate_limit>\\d+\\.\\d+))?(?:.*?'openAI':\\s*(?<openAI>\\d+\\.\\d+))?(?:.*?'cosmosDB':\\s*(?<cosmosDB>\\d+\\.\\d+))?(?:.*?'cosmosDB\\.logging_prompt':\\s*(?<cosmosDB_logging_prompt>\\d+\\.\\d+))?(?:.*?'cosmosDB\\.logging_consumption':\\s*(?<cosmosDB_logging_consumption>\\d+\\.\\d+))?(?:.*?'redis\\.logging_consumption':\\s*(?<redis_logging_consumption>\\d+\\.\\d+))?.*}")

// Step 3: Sum the component latencies for each request.
| total_component_latency := redis +  openAI + cosmosDB 

// Step 4: Group requests into 5-minute buckets and calculate the P95 latency for each bucket.
| timechart(span=5m, function=[percentile(field=total_component_latency, percentiles=[95], as=latency)])

// Step 5: For each 5-minute bucket, flag if its P95 latency exceeds the 100-second SLO target.
| is_slo_failure := if(latency_95 > 50, then=1, else=0)

// Step 6: Aggregate the results to find the total number of intervals and the number of failed intervals.
| [sum(is_slo_failure, as=failed_intervals), count(as=total_intervals)]

// Step 7: Calculate the actual percentage of time intervals that failed the SLO.
| percent_of_time_failed := if(total_intervals > 0, then=((failed_intervals / total_intervals) * 100), else=0)

// Step 8: Calculate the error budget used as a percentage of the allowed budget (5% for a 95% SLO).
| error_budget_used_percent := if(percent_of_time_failed > 0, then=((percent_of_time_failed / 5) * 100), else=0)

// Step 9: Display the final error budget used percentage.
| select(error_budget_used_percent)

